// Download helper
function downloadEvidence(filename) {
  const data = EVIDENCE_IMAGES[filename];
  if (!data) return;
  const a = document.createElement('a');
  a.href = data;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
}

